(() => {
    interface Settings {
      display: {theme: 'light' | 'dark'; brightness: number};
      audio: {volume: number; muted: boolean};
    }
    type DeepPartial<T> = {[K in keyof T]?: T[K] extends object ? DeepPartial<T[K]> : T[K]};
    return {build: () => createValidate<DeepPartial<Settings>>(), buildErrors: () => noErrs(createGetValidationErrors<DeepPartial<Settings>>())};
  })()

() =>
    createValidate(
      RT.object({
        display: RT.optional(
          RT.object({
            theme: RT.optional(RT.union([RT.literal('light'), RT.literal('dark')])),
            brightness: RT.optional(RT.number()),
          })
        ),
        audio: RT.optional(RT.object({volume: RT.optional(RT.number()), muted: RT.optional(RT.boolean())})),
      })
    )

c( // override: TypeBox accepts new Date() for all-optional outer object — drop it from invalid
    Type.Object({
      display: Type.Optional(Type.Object({
        theme: Type.Optional(Type.Union([Type.Literal('light'), Type.Literal('dark')])),
        brightness: Type.Optional(Type.Number()),
      })),
      audio: Type.Optional(Type.Object({
        volume: Type.Optional(Type.Number()),
        muted: Type.Optional(Type.Boolean()),
      })),
    }),
    {
      valid: [
        {},
        {display: {}},
        {audio: {volume: 1}},
        {display: {theme: 'light'}, audio: {muted: true}},
        {display: {theme: 'dark', brightness: 0.5}, audio: {volume: 1, muted: false}},
      ],
      invalid: [[], {display: 'not object'}, {display: {theme: 'invalid'}}, {audio: {volume: NaN}}, null, undefined],
    },
  )

c(z.custom((v) => {
    if (typeof v !== 'object' || v === null) return false;
    if (Object.prototype.toString.call(v) !== '[object Object]') return false;
    const obj = v as Record<string, unknown>;
    if ('display' in obj && obj.display !== undefined) {
      if (typeof obj.display !== 'object' || obj.display === null || typeof (obj.display as Date).getTime === 'function') return false;
      const disp = obj.display as Record<string, unknown>;
      if ('theme' in disp && disp.theme !== undefined && disp.theme !== 'light' && disp.theme !== 'dark') return false;
      if ('brightness' in disp && disp.brightness !== undefined && (typeof disp.brightness !== 'number' || !Number.isFinite(disp.brightness))) return false;
    }
    if ('audio' in obj && obj.audio !== undefined) {
      if (typeof obj.audio !== 'object' || obj.audio === null) return false;
      const audio = obj.audio as Record<string, unknown>;
      if ('volume' in audio && audio.volume !== undefined && (typeof audio.volume !== 'number' || !Number.isFinite(audio.volume))) return false;
      if ('muted' in audio && audio.muted !== undefined && typeof audio.muted !== 'boolean') return false;
    }
    return true;
  }))
